const ctx=$json.ctx;
const rules='You are tnAI, writing the Managing Director of Tecknuovo one MACRO STORY per account, from the past week\'s data below (signals with quotes, the calls they came from, the latest weekly delivery report, open pipeline). For EACH account in the data produce: headline = 1-2 sentences, the so-what an MD absorbs in five seconds (name the biggest thing, with numbers where the data has them). story = an IN-DEPTH analysis of 2-3 full paragraphs: what actually happened across this account\'s calls this week and the thread connecting them; the risks in context - what is driving them, whether they are one-offs or a pattern, how severe, and call out anything sitting unresolved with its age in days; the commercial side - opportunities, their NETWORKS strength, any value mentioned, how the pipeline looks; and close with where this account is heading and what should happen next, naming who should act where the data suggests it. Be precise and analytical, never generic - every claim anchored in the data, quote fragments woven in where they carry weight. Judge everything from Tecknuovo\'s perspective. Plain UK business English. Never use em dashes; use commas or hyphens. Return ONLY JSON: {"items":[{"account":"exact account name","headline":"...","story":"paragraphs separated by \\n\\n"}]}';
const prompt=rules+'\n\nTHE WEEK\'S DATA:\n'+JSON.stringify(ctx);
return [{json:{prompt}}];

const raw=($json.text||$json.response||$json.output||'').trim();
// The model often puts LITERAL newlines inside JSON strings (the paragraphs we ask
// for) - invalid JSON. Escape control chars inside strings, then parse.
function parseModelJson(t){
  const m=t.match(/\{[\s\S]*\}/); if(!m){return null;}
  let s=m[0];
  try{return JSON.parse(s);}catch(e){}
  let out='',inStr=false,esc=false;
  for(const ch of s){
    if(esc){out+=ch;esc=false;continue;}
    if(ch==='\\'){out+=ch;esc=true;continue;}
    if(ch==='"'){inStr=!inStr;out+=ch;continue;}
    if(inStr&&ch==='\n'){out+='\\n';continue;}
    if(inStr&&ch==='\r'){continue;}
    if(inStr&&ch==='\t'){out+='\\t';continue;}
    out+=ch;
  }
  try{return JSON.parse(out);}catch(e){return null;}
}
const obj=parseModelJson(raw);
if(!obj){return [{json:{sql:"SELECT 'model output could not be parsed' AS note", parse_error:true, raw_head:raw.slice(0,300)}}];}
const items=Array.isArray(obj.items)?obj.items.slice(0,10).map(function(x){return {
 account:String((x&&x.account)||'').slice(0,120),
 headline:String((x&&x.headline)||'').slice(0,400),
 story:String((x&&x.story)||'').slice(0,4000)
}}).filter(function(x){return x.account&&x.story}):[];
if(!items.length){return [{json:{sql:"SELECT 'no items - nothing saved' AS note", found:0}}];}
const e=function(s){return String(s).replace(/'/g,"''")};
const sql="INSERT INTO briefs (audience,period_start,period_end,content) VALUES ('stories', now()::date-7, now()::date, '"+e(JSON.stringify({items:items}))+"'::jsonb);";
return [{json:{sql,accounts:items.length}}];
